import { useState, useEffect, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const menuItems = ["Dashboard", "Products", "Orders", "Users", "Analytics", "Settings"];

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState("");

  // Auto open sidebar on large screens
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) {
        setIsOpen(true);
      } else {
        setIsOpen(false);
      }
    };

    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Filter sidebar items
  const filteredMenu = useMemo(() => {
    return menuItems.filter((item) =>
      item.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  return (
    <div className={design.layout.wrapper}>

      {/* 🔥 TOP NAVBAR (FULL WIDTH) */}
      <div className={design.layout.navbar}>
        
        {/* Mobile Toggle */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="lg:hidden text-gray-700 text-xl"
        >
          ☰
        </button>

        {/* Search Field */}
        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.colors.input}
        />

        {/* Admin Info */}
        <div className="flex items-center gap-3">
          <span className="text-sm text-gray-600">
            {adminInfo?.name}
          </span>
          <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
        </div>
      </div>

      {/* 🔥 BODY */}
      <div className={design.layout.body}>

        {/* Sidebar */}
        <AnimatePresence>
          {isOpen && (
            <motion.aside
              initial={{ x: -260 }}
              animate={{ x: 0 }}
              exit={{ x: -260 }}
              transition={{ duration: 0.3 }}
              className={`${design.colors.sidebar} ${design.layout.sidebar} fixed lg:static h-full z-50`}
            >
              <h2 className="text-xl font-bold text-indigo-400">
                Admin Panel
              </h2>

              <nav className="space-y-2">
                {filteredMenu.length > 0 ? (
                  filteredMenu.map((item, index) => (
                    <div
                      key={index}
                      className={`${design.layout.navItem} ${design.colors.hover}`}
                    >
                      {item}
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-gray-400">No results</p>
                )}
              </nav>
            </motion.aside>
          )}
        </AnimatePresence>

        {/* Overlay (mobile only) */}
        {isOpen && window.innerWidth < 1024 && (
          <div
            className={`fixed inset-0 ${design.colors.overlay} z-40`}
            onClick={() => setIsOpen(false)}
          />
        )}

        {/* Content */}
        <div className={design.layout.content}>
          <motion.div
            initial={{ opacity: 0, y: 15 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <h1 className="text-2xl lg:text-3xl font-bold mb-4">
              Welcome Back 👋
            </h1>

            <p className="text-gray-600">
              Professional admin dashboard layout with searchable sidebar.
            </p>
          </motion.div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
